<?php
session_start(); require 'db_connection.php'; require_once 'helpers.php'; require_admin(); $conn=OpenCon();
$month=$_GET['month']??''; $year=$_GET['year']??''; $userId=$_GET['user_id']??''; $productId=$_GET['product_id']??''; $min=$_GET['min_price']??''; $max=$_GET['max_price']??''; $sort=$_GET['sort_price']??'';
$sql="SELECT DISTINCT o.id,o.total_price,o.order_type,o.order_status,o.created_at,u.first_name,u.email FROM orders o JOIN users u ON u.id=o.user_id LEFT JOIN order_items oi ON oi.order_id=o.id WHERE 1=1"; $types=''; $params=[];
if($month!==''){ $sql.=" AND MONTH(o.created_at)=?"; $types.='i'; $params[]=(int)$month; } if($year!==''){ $sql.=" AND YEAR(o.created_at)=?"; $types.='i'; $params[]=(int)$year; } if($userId!==''){ $sql.=" AND o.user_id=?"; $types.='i'; $params[]=(int)$userId; } if($productId!==''){ $sql.=" AND oi.product_id=?"; $types.='i'; $params[]=(int)$productId; } if($min!==''){ $sql.=" AND o.total_price>=?"; $types.='d'; $params[]=(float)$min; } if($max!==''){ $sql.=" AND o.total_price<=?"; $types.='d'; $params[]=(float)$max; }
$sql.=$sort==='asc'?" ORDER BY o.total_price ASC":($sort==='desc'?" ORDER BY o.total_price DESC":" ORDER BY o.created_at DESC"); $stmt=$conn->prepare($sql); if($params){$stmt->bind_param($types,...$params);} $stmt->execute(); $orders=$stmt->get_result(); $users=$conn->query("SELECT id,first_name FROM users ORDER BY first_name"); $products=$conn->query("SELECT id,name FROM products ORDER BY name");
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Orders Report</title><link rel="stylesheet" href="css/style.css"></head><body><?php include 'navbar.php'; ?><div class="admin-container"><h2>Orders Report</h2><form method="get" class="card"><div class="grid"><label>Month<select name="month"><option value="">All</option><?php for($m=1;$m<=12;$m++):?><option value="<?=$m?>" <?=$month==$m?'selected':''?>><?=$m?></option><?php endfor;?></select></label><label>Year<select name="year"><option value="">All</option><?php for($y=2023;$y<=2027;$y++):?><option value="<?=$y?>" <?=$year==$y?'selected':''?>><?=$y?></option><?php endfor;?></select></label><label>Customer<select name="user_id"><option value="">All</option><?php while($u=$users->fetch_assoc()):?><option value="<?=(int)$u['id']?>" <?=$userId==$u['id']?'selected':''?>><?=e($u['first_name'])?></option><?php endwhile;?></select></label><label>Product<select name="product_id"><option value="">All</option><?php while($p=$products->fetch_assoc()):?><option value="<?=(int)$p['id']?>" <?=$productId==$p['id']?'selected':''?>><?=e($p['name'])?></option><?php endwhile;?></select></label><label>Min Price<input type="number" name="min_price" value="<?=e($min)?>"></label><label>Max Price<input type="number" name="max_price" value="<?=e($max)?>"></label><label>Sort<select name="sort_price"><option value="">Newest</option><option value="asc" <?=$sort==='asc'?'selected':''?>>Low → High</option><option value="desc" <?=$sort==='desc'?'selected':''?>>High → Low</option></select></label></div><button>Search</button></form><br><table><tr><th>ID</th><th>User</th><th>Email</th><th>Total</th><th>Type</th><th>Status</th><th>Date</th><th>Details</th></tr><?php while($r=$orders->fetch_assoc()):?><tr><td><?=(int)$r['id']?></td><td><?=e($r['first_name'])?></td><td><?=e($r['email'])?></td><td>$<?=number_format((float)$r['total_price'],2)?></td><td><?=e(strtoupper($r['order_type']))?></td><td><?=e($r['order_status'])?></td><td><?=e($r['created_at'])?></td><td><a href="order_details.php?order_id=<?=(int)$r['id']?>">View</a></td></tr><?php endwhile;?></table></div></body></html>
